program
	.command("confluence-get-comments")
	.summary("confluence-get-comments --page-id <page-id> [--raw <json>]")
	.description("Get comments for a specific Confluence page.\n\nArgs:\n    ctx: The FastMCP context.\n    page_id: Confluence page ID.\n\nReturns:\n    JSON string representing a list of comment objects.")
	.usage("--page-id <page-id> [--raw <json>]")
	.option('--raw <json>', 'Provide raw JSON arguments to the tool, bypassing flag parsing.')

	.option("--page-id <page-id>", "Confluence page ID (numeric ID, can be parsed from URL, e.g. from 'https://example.atlassian.net/wiki/spaces/TEAM/pages/123456789/Page+Title' -> '123456789') (example: example-id)")
	
	.alias("confluence_get_comments")	.action(async (cmdOpts) => {
		const globalOptions = program.opts();
		const runtimeContext = await ensureRuntime();
		const runtime = runtimeContext.runtime;
		const serverName = embeddedName;
		const proxy = createServerProxy(runtime, serverName, {
			initialSchemas: embeddedSchemas,
		});
		try {
			const args = cmdOpts.raw ? JSON.parse(cmdOpts.raw) : ({} as Record<string, unknown>);
			if (!cmdOpts.raw) {
				const missingRequired = [{ value: cmdOpts.pageId, flag: "--page-id" }].filter((entry) => entry.value === undefined).map((entry) => entry.flag);
			if (missingRequired.length > 0) {
				throw new Error('Missing required option' + (missingRequired.length === 1 ? '' : 's') + ': ' + missingRequired.join(', '));
			}
				if (cmdOpts.pageId !== undefined) args.page_id = cmdOpts.pageId;
			}
			const call = (proxy.confluenceGetComments as any)(args);
			const result = await invokeWithTimeout(call, globalOptions.timeout || 30000);
			printResult(result, globalOptions.output ?? 'text');
		} finally {
			await runtimeContext.close(serverName).catch(() => {});
		}
	})
	.addHelpText('after', () => '\nExample:\n  ' + "mcporter call util_rusklimat_atlassian.confluence_get_comments(page_id: \"e, ...)");

