program
	.command("confluence-get-page")
	.summary("confluence-get-page [--page-id <page-id>] [--title <title>] [--space-key <space-key>] [--include-metadata <include-metadata:true|false>] [--convert-to-markdown <convert-to-markdown:true|false>] [--raw <json>]")
	.description("Get content of a specific Confluence page by its ID, or by its title and space key.\n\nArgs:\n    ctx: The FastMCP context.\n    page_id: Confluence page ID. If provided, 'title' and 'space_key' are ignored.\n    title: The exact title of the page. Must be used with 'space_key'.\n    space_key: The key of the space. Must be used with 'title'.\n    include_metadata: Whether to include page metadata.\n    convert_to_markdown: Convert content to markdown (true) or keep raw HTML (false).\n\nReturns:\n    JSON string representing the page content and/or metadata, or an error if not found or parameters are invalid.")
	.usage("[--page-id <page-id>] [--title <title>] [--space-key <space-key>] [--include-metadata <include-metadata:true|false>] [--convert-to-markdown <convert-to-markdown:true|false>] [--raw <json>]")
	.option('--raw <json>', 'Provide raw JSON arguments to the tool, bypassing flag parsing.')

	.option("--page-id <page-id>", "Confluence page ID (numeric ID, can be found in the page URL). For example, in the URL 'https://example.atlassian.net/wiki/spaces/TEAM/pages/123456789/Page+Title', the page ID is '123456789'. Provide this OR both 'title' and 'space_key'. If page_id is provided, title and space_key will be ignored. (default: null; example: null)")
	.option("--title <title>", "The exact title of the Confluence page. Use this with 'space_key' if 'page_id' is not known. (default: null; example: null)")
	.option("--space-key <space-key>", "The key of the Confluence space where the page resides (e.g., 'DEV', 'TEAM'). Required if using 'title'. (default: null; example: null)")
	.option("--include-metadata <include-metadata:true|false>", "Whether to include page metadata such as creation date, last update, version, and labels. (default: true; example: true)", (value) => value !== 'false')
	.option("--convert-to-markdown <convert-to-markdown:true|false>", "Whether to convert page to markdown (true) or keep it in raw HTML format (false). Raw HTML can reveal macros (like dates) not visible in markdown, but CAUTION: using HTML significantly increases token usage in AI responses. (default: true; example: true)", (value) => value !== 'false')
	
	.alias("confluence_get_page")	.action(async (cmdOpts) => {
		const globalOptions = program.opts();
		const runtimeContext = await ensureRuntime();
		const runtime = runtimeContext.runtime;
		const serverName = embeddedName;
		const proxy = createServerProxy(runtime, serverName, {
			initialSchemas: embeddedSchemas,
		});
		try {
			const args = cmdOpts.raw ? JSON.parse(cmdOpts.raw) : ({} as Record<string, unknown>);
			if (!cmdOpts.raw) {
				
				if (cmdOpts.pageId !== undefined) args.page_id = cmdOpts.pageId;
		if (cmdOpts.title !== undefined) args.title = cmdOpts.title;
		if (cmdOpts.spaceKey !== undefined) args.space_key = cmdOpts.spaceKey;
		if (cmdOpts.includeMetadata !== undefined) args.include_metadata = cmdOpts.includeMetadata;
		if (cmdOpts.convertToMarkdown !== undefined) args.convert_to_markdown = cmdOpts.convertToMarkdown;
			}
			const call = (proxy.confluenceGetPage as any)(args);
			const result = await invokeWithTimeout(call, globalOptions.timeout || 30000);
			printResult(result, globalOptions.output ?? 'text');
		} finally {
			await runtimeContext.close(serverName).catch(() => {});
		}
	})
	.addHelpText('after', () => '\nExample:\n  ' + "mcporter call util_rusklimat_atlassian.confluence_get_page(page_id: \"null\", ...)");

