program
	.command("confluence-search")
	.summary("confluence-search --query <query> [--limit <limit:number>] [--spaces-filter <spaces-filter>] [--raw <json>]")
	.description("Search Confluence content using simple terms or CQL.\n\nArgs:\n    ctx: The FastMCP context.\n    query: Search query - can be simple text or a CQL query string.\n    limit: Maximum number of results (1-50).\n    spaces_filter: Comma-separated list of space keys to filter by.\n\nReturns:\n    JSON string representing a list of simplified Confluence page objects.")
	.usage("--query <query> [--limit <limit:number>] [--spaces-filter <spaces-filter>] [--raw <json>]")
	.option('--raw <json>', 'Provide raw JSON arguments to the tool, bypassing flag parsing.')

	.option("--query <query>", "Search query - can be either a simple text (e.g. 'project documentation') or a CQL query string. Simple queries use 'siteSearch' by default, to mimic the WebUI search, with an automatic fallback to 'text' search if not supported. Examples of CQL:\n- Basic search: 'type=page AND space=DEV'\n- Personal space search: 'space=\"~username\"' (note: personal space keys starting with ~ must be quoted)\n- Search by title: 'title~\"Meeting Notes\"'\n- Use siteSearch: 'siteSearch ~ \"important concept\"'\n- Use text search: 'text ~ \"important concept\"'\n- Recent content: 'created >= \"2023-01-01\"'\n- Content with specific label: 'label=documentation'\n- Recently modified content: 'lastModified > startOfMonth(\"-1M\")'\n- Content modified this year: 'creator = currentUser() AND lastModified > startOfYear()'\n- Content you contributed to recently: 'contributor = currentUser() AND lastModified > startOfWeek()'\n- Content watched by user: 'watcher = \"user@domain.com\" AND type = page'\n- Exact phrase in content: 'text ~ \"\\\"Urgent Review Required\\\"\" AND label = \"pending-approval\"'\n- Title wildcards: 'title ~ \"Minutes*\" AND (space = \"HR\" OR space = \"Marketing\")'\nNote: Special identifiers need proper quoting in CQL: personal space keys (e.g., \"~username\"), reserved words, numeric IDs, and identifiers with special characters.")
	.option("--limit <limit:number>", "Maximum number of results (1-50) (default: 10; example: 10)", (value) => parseFloat(value))
	.option("--spaces-filter <spaces-filter>", "(Optional) Comma-separated list of space keys to filter results by. Overrides the environment variable CONFLUENCE_SPACES_FILTER if provided. Use empty string to disable filtering. (default: null; example: null)")
	
	.alias("confluence_search")	.action(async (cmdOpts) => {
		const globalOptions = program.opts();
		const runtimeContext = await ensureRuntime();
		const runtime = runtimeContext.runtime;
		const serverName = embeddedName;
		const proxy = createServerProxy(runtime, serverName, {
			initialSchemas: embeddedSchemas,
		});
		try {
			const args = cmdOpts.raw ? JSON.parse(cmdOpts.raw) : ({} as Record<string, unknown>);
			if (!cmdOpts.raw) {
				const missingRequired = [{ value: cmdOpts.query, flag: "--query" }].filter((entry) => entry.value === undefined).map((entry) => entry.flag);
			if (missingRequired.length > 0) {
				throw new Error('Missing required option' + (missingRequired.length === 1 ? '' : 's') + ': ' + missingRequired.join(', '));
			}
				if (cmdOpts.query !== undefined) args.query = cmdOpts.query;
		if (cmdOpts.limit !== undefined) args.limit = cmdOpts.limit;
		if (cmdOpts.spacesFilter !== undefined) args.spaces_filter = cmdOpts.spacesFilter;
			}
			const call = (proxy.confluenceSearch as any)(args);
			const result = await invokeWithTimeout(call, globalOptions.timeout || 30000);
			printResult(result, globalOptions.output ?? 'text');
		} finally {
			await runtimeContext.close(serverName).catch(() => {});
		}
	})
	.addHelpText('after', () => '\nExample:\n  ' + "mcporter call util_rusklimat_atlassian.confluence_search(query: \"value\", l, ...)");

