program
	.command("jira-add-comment")
	.summary("jira-add-comment --issue-key <issue-key> --body <body> [--visibility <visibility>] [--public <public:true|false>] [--raw <json>]")
	.description("Add a comment to a Jira issue.\n\nArgs:\n    ctx: The FastMCP context.\n    issue_key: Jira issue key.\n    body: Comment text in Markdown.\n    visibility: (Optional) Comment visibility as JSON string.\n    public: (Optional) For JSM issues. True = customer-visible,\n        False = internal/agent-only. Uses ServiceDesk API.\n\nReturns:\n    JSON string representing the added comment object.\n\nRaises:\n    ValueError: If in read-only mode or Jira client unavailable.")
	.usage("--issue-key <issue-key> --body <body> [--visibility <visibility>] [--public <public:true|false>] [--raw <json>]")
	.option('--raw <json>', 'Provide raw JSON arguments to the tool, bypassing flag parsing.')

	.option("--issue-key <issue-key>", "Jira issue key (e.g., 'PROJ-123', 'ACV2-642')")
	.option("--body <body>", "Comment text in Markdown format")
